CREATE TABLE IF NOT EXISTS ""caregivers"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""user_id"" VARCHAR NOT NULL, ""relationship"" text NOT NULL, ""role"" text NOT NULL DEFAULT 'viewer'::text, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""children"" (""id"" integer NOT NULL, ""name"" text NOT NULL, ""birth_date"" date NOT NULL, ""gender"" text NOT NULL, ""theme"" text DEFAULT 'neutral'::text, ""theme_color"" text, ""initial_weight"" numeric, ""initial_height"" numeric, ""initial_head_circumference"" numeric, ""photo_url"" text, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""daily_photos"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""date"" date NOT NULL, ""photo_url"" text NOT NULL, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""diary_entries"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""date"" date NOT NULL, ""content"" text, ""photo_urls"" _text[], ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""gamification"" (""id"" integer NOT NULL, ""points"" integer DEFAULT 0, ""level"" text DEFAULT 'Iniciante'::text, ""achievements"" jsonb DEFAULT '[]'::jsonb, ""updated_at"" timestamp without time zone DEFAULT now(), ""child_id"" integer NOT NULL);

CREATE TABLE IF NOT EXISTS ""growth_records"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""date"" date NOT NULL, ""weight"" numeric, ""height"" numeric, ""head_circumference"" numeric, ""notes"" text, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""health_records"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""date"" date NOT NULL, ""symptoms"" text NOT NULL, ""diagnosis"" text, ""medication"" text, ""notes"" text, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""invite_codes"" (""id"" integer NOT NULL, ""code"" VARCHAR(10) NOT NULL, ""child_id"" integer NOT NULL, ""created_by"" VARCHAR NOT NULL, ""used_by"" VARCHAR, ""relationship"" text NOT NULL DEFAULT 'caregiver'::text, ""expires_at"" timestamp without time zone NOT NULL, ""used_at"" timestamp without time zone, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""milestones"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""date"" date NOT NULL, ""title"" text NOT NULL, ""description"" text, ""photo_url"" text, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""push_subscriptions"" (""id"" integer NOT NULL, ""user_id"" VARCHAR NOT NULL, ""endpoint"" text NOT NULL, ""p256dh"" text NOT NULL, ""auth"" text NOT NULL, ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""sessions"" (""sid"" VARCHAR NOT NULL, ""sess"" jsonb NOT NULL, ""expire"" timestamp without time zone NOT NULL);

CREATE TABLE IF NOT EXISTS ""sus_vaccines"" (""id"" integer NOT NULL, ""name"" text NOT NULL, ""diseases_prevented"" text NOT NULL, ""recommended_doses"" text NOT NULL, ""age_range"" text);

CREATE TABLE IF NOT EXISTS ""users"" (""id"" VARCHAR NOT NULL DEFAULT gen_random_uuid(), ""email"" VARCHAR, ""first_name"" VARCHAR, ""last_name"" VARCHAR, ""profile_image_url"" VARCHAR, ""created_at"" timestamp without time zone DEFAULT now(), ""updated_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""vaccine_records"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""sus_vaccine_id"" integer NOT NULL, ""dose"" text NOT NULL, ""application_date"" date NOT NULL, ""application_place"" text, ""notes"" text, ""photo_urls"" _text[], ""created_at"" timestamp without time zone DEFAULT now());

CREATE TABLE IF NOT EXISTS ""vaccines"" (""id"" integer NOT NULL, ""child_id"" integer NOT NULL, ""name"" text NOT NULL, ""scheduled_date"" date NOT NULL, ""administered_date"" date, ""status"" text NOT NULL DEFAULT 'pending'::text, ""notes"" text, ""created_at"" timestamp without time zone DEFAULT now());"


